import React from "react"
import { graphql, useStaticQuery } from "gatsby"
import { GatsbyImage, getImage } from "gatsby-plugin-image"

export default function Partners() {
  let data = useStaticQuery(graphql`
    query {
      brand1: file(relativePath: { eq: "partners/brand-1.png" }) {
        childImageSharp {
          gatsbyImageData(placeholder: BLURRED, formats: [AUTO, WEBP, AVIF])
        }
      },
        brand2: file(relativePath: { eq: "partners/brand-2.png" }) {
        childImageSharp {
          gatsbyImageData(placeholder: BLURRED, formats: [AUTO, WEBP, AVIF])
        }
      },
        brand3: file(relativePath: { eq: "partners/brand-3.png" }) {
        childImageSharp {
          gatsbyImageData(placeholder: BLURRED, formats: [AUTO, WEBP, AVIF])
        }
      },
        brand4: file(relativePath: { eq: "partners/brand-4.png" }) {
        childImageSharp {
          gatsbyImageData(placeholder: BLURRED, formats: [AUTO, WEBP, AVIF])
        }
      },
        brand5: file(relativePath: { eq: "partners/brand-5.png" }) {
        childImageSharp {
          gatsbyImageData(placeholder: BLURRED, formats: [AUTO, WEBP, AVIF])
        }
      }
    }
  `)

  return (
    <section class="construct-partners-area section_50">
      <div class="container">
        <div class="row">
          <div class="col-md-12">
            <div autoplay={true}
              loop={true}
              margin={20}
              touchDrag={true}
              mouseDrag={true}
              nav={false}
              dots={false}
              autoplayTimeout={6000}
              autoplaySpeed={1200}
              autoplayHoverPause={true}
              responsive={{
                0: {
                  items: 2
                },
                480: {
                  items: 2
                },
                600: {
                  items: 4
                },
                1000: {
                  items: 5
                },
                1200: {
                  items: 5
                }
              }} class="partners-slider">
              <div class="single-partners">
                <GatsbyImage
                  image={getImage(data.brand1.childImageSharp)}
                  alt="Brand1"
                />
              </div>
              <div class="single-partners">
                <GatsbyImage
                  image={getImage(data.brand2.childImageSharp)}
                  alt="Brand1"
                />
              </div>
              <div class="single-partners">
                <GatsbyImage
                  image={getImage(data.brand3.childImageSharp)}
                  alt="Brand1"
                />
              </div>
              <div class="single-partners">
                <GatsbyImage
                  image={getImage(data.brand4.childImageSharp)}
                  alt="Brand1"
                />
              </div>
              <div class="single-partners">
                <GatsbyImage
                  image={getImage(data.brand5.childImageSharp)}
                  alt="Brand1"
                />
              </div>
            </div>
          </div>
        </div>
      </div>
    </section>

  )
}